// Best fix: remove selfdestruct entirely. It is deprecated (EIP-6780)
// and its behavior changed after the Cancun hardfork.
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract Vault is Ownable {
    // Instead of selfdestruct, add a pausable / sunset flag and a
    // guarded sweep of remaining funds:
    bool public retired;

    function retire(address payable treasury) external onlyOwner {
        retired = true;
        (bool ok, ) = treasury.call{value: address(this).balance}("");
        require(ok, "sweep failed");
    }

    modifier notRetired() {
        require(!retired, "contract retired");
        _;
    }

    // If you absolutely must keep selfdestruct (legacy chains only),
    // gate it behind strict access control and never expose it in a
    // library or implementation contract used behind a proxy:
    // function destroy() external onlyOwner { selfdestruct(payable(owner())); }
}
